import React from "react";
import Navbar from "../components/Navbar";
import "../styles/home.css";

const Home = () => {
  return (
    <div>

      <Navbar />

      {/* HERO */}
      <div className="hero-section text-center text-white d-flex flex-column justify-content-center align-items-center">

        <h1 className="hero-title">
          Find Skilled Workers Instantly
        </h1>

        <p className="hero-subtitle">
          Hire Labour or Get Work Near You
        </p>

        <div className="mt-4">
          <a href="/login" className="btn btn-primary me-3">
            Hire Worker
          </a>

          <a href="/login" className="btn btn-success">
            Get Work
          </a>
        </div>

      </div>

    </div>
  );
};

export default Home;
